import{_ as o,o as t,c as a,ag as d}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"附录 C：名词解释（Glossary）","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/appendix-c-glossary.md","filePath":"chapters/appendix-c-glossary.md"}'),c={name:"chapters/appendix-c-glossary.md"};function s(n,e,r,p,i,l){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="附录-c-名词解释-glossary" tabindex="-1">附录 C：名词解释（Glossary） <a class="header-anchor" href="#附录-c-名词解释-glossary" aria-label="Permalink to &quot;附录 C：名词解释（Glossary）&quot;">​</a></h1><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><p><strong>Agent</strong> Pydantic AI 的核心类，封装了模型调用、工具执行、结果验证的完整 Agent 流程。通过泛型参数 <code>Agent[AgentDepsT, OutputDataT]</code> 实现类型安全。详见第 3 章。</p><p><strong>AgentDepsT</strong> Agent 的依赖类型参数，表示通过 <code>RunContext</code> 注入的依赖对象的类型。可以是任意 Python 类型，如 <code>str</code>、<code>dataclass</code> 或自定义类。详见第 6 章。</p><p><strong>AgentModel</strong> 运行时模型接口，由 <code>Model.agent_model()</code> 方法创建。它已绑定工具定义和模型配置，负责实际的请求发送和响应处理。定义于 <code>pydantic_ai/models/__init__.py</code>。详见第 7 章。</p><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><p><strong>EndStrategy</strong> Agent 运行的结束策略，控制当模型同时返回文本和工具调用时的行为。取值为 <code>&#39;early&#39;</code>（立即结束）或 <code>&#39;exhaustive&#39;</code>（执行完所有工具调用后结束）。详见第 4 章。</p><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><p><strong>FunctionModel</strong> 测试专用模型，将响应生成逻辑委托给用户提供的函数。适用于需要根据输入动态生成响应的测试场景。定义于 <code>pydantic_ai/models/test.py</code>。详见第 18 章。</p><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><p><strong>InstrumentationSettings</strong> 控制 Logfire 追踪行为的配置类。通过 <code>Agent</code> 构造函数的 <code>instrument</code> 参数传入，激活 OpenTelemetry span 追踪。详见第 17 章。</p><h2 id="k" tabindex="-1">K <a class="header-anchor" href="#k" aria-label="Permalink to &quot;K&quot;">​</a></h2><p><strong>KnownModelName</strong> 预定义的模型名称字面量类型，如 <code>&#39;openai:gpt-4o&#39;</code>、<code>&#39;anthropic:claude-3-5-sonnet&#39;</code>、<code>&#39;gemini-1.5-pro&#39;</code> 等。框架根据该名称自动选择对应的模型适配器。详见第 7 章。</p><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><p><strong>MCP</strong> Model Context Protocol 的缩写，由 Anthropic 提出的开放标准协议，用于标准化 AI 应用与外部工具服务之间的通信。Pydantic AI 原生支持 MCP 客户端集成。详见第 13 章。</p><p><strong>MCPServerHTTP</strong> 基于 HTTP SSE 传输的 MCP 服务器连接配置。适用于远程部署的 MCP 服务，通过 HTTP 协议通信。定义于 <code>pydantic_ai/mcp.py</code>。详见第 13 章。</p><p><strong>MCPServerStdio</strong> 基于标准输入输出传输的 MCP 服务器连接配置。通过子进程方式启动本地 MCP 服务器，使用 stdin/stdout 通信。定义于 <code>pydantic_ai/mcp.py</code>。详见第 13 章。</p><p><strong>Model</strong> 所有模型适配器的抽象基类，定义了 <code>agent_model()</code> 方法作为核心协议。具体模型（如 OpenAI、Anthropic）通过继承该类实现适配。定义于 <code>pydantic_ai/models/__init__.py</code>。详见第 7 章。</p><p><strong>ModelMessage</strong> 消息体系的顶层联合类型，定义为 <code>ModelRequest | ModelResponse</code>。Agent 的对话历史由 <code>ModelMessage</code> 列表组成。定义于 <code>pydantic_ai/messages.py</code>。详见第 9 章。</p><p><strong>ModelRequest</strong> 发送给模型的请求消息，包含 <code>SystemPromptPart</code>、<code>UserPromptPart</code>、<code>ToolReturnPart</code> 和 <code>RetryPromptPart</code> 四种 Part 类型。定义于 <code>pydantic_ai/messages.py</code>。详见第 9 章。</p><p><strong>ModelResponse</strong> 模型返回的响应消息，包含 <code>TextPart</code> 和 <code>ToolCallPart</code> 两种 Part 类型。定义于 <code>pydantic_ai/messages.py</code>。详见第 9 章。</p><p><strong>ModelRetry</strong> 工具函数抛出的异常类型，用于请求模型重新生成工具调用参数。Agent 会将错误信息作为 <code>RetryPromptPart</code> 发送给模型。定义于 <code>pydantic_ai/exceptions.py</code>。详见第 14 章。</p><p><strong>ModelSettings</strong> 传递给模型的参数集合，使用 <code>TypedDict</code> 定义。包含 <code>max_tokens</code>、<code>temperature</code>、<code>top_p</code> 等通用参数。定义于 <code>pydantic_ai/settings.py</code>。详见第 7 章和附录 B。</p><h2 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to &quot;O&quot;">​</a></h2><p><strong>OutputDataT</strong> Agent 的输出类型参数，表示 <code>RunResult.output</code> 的类型。默认为 <code>str</code>，可以设置为 Pydantic <code>BaseModel</code> 子类以实现结构化输出。详见第 3 章和第 12 章。</p><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><p><strong>RunContext</strong> 工具函数和动态提示函数接收的运行时上下文对象。通过泛型参数 <code>RunContext[AgentDepsT]</code> 携带类型安全的依赖引用，同时提供 <code>usage</code>、<code>messages</code> 等运行时信息。定义于 <code>pydantic_ai/tools.py</code>。详见第 6 章。</p><p><strong>RunResult</strong> Agent 单次运行的结果封装，携带类型安全的输出数据 <code>output</code>，以及消息历史、token 消耗等元信息。定义于 <code>pydantic_ai/result.py</code>。详见第 12 章。</p><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><p><strong>StreamedRunResult</strong> Agent 流式运行的结果封装，作为异步上下文管理器使用。提供 <code>stream_text()</code> 和 <code>stream_structured()</code> 方法逐块获取输出。定义于 <code>pydantic_ai/result.py</code>。详见第 10 章和第 12 章。</p><p><strong>SystemPromptPart</strong> 系统提示消息部分，包含 Agent 的系统级指令文本。可以是静态字符串，也可以通过 <code>@agent.system_prompt</code> 装饰器动态生成。定义于 <code>pydantic_ai/messages.py</code>。详见第 9 章。</p><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><p><strong>TestModel</strong> 测试专用模型，返回预定义的确定性响应。支持通过 <code>custom_output_text</code> 和 <code>custom_output_args</code> 控制输出内容，通过 <code>call_tools</code> 模拟工具调用。定义于 <code>pydantic_ai/models/test.py</code>。详见第 18 章。</p><p><strong>TextPart</strong> 模型响应中的文本内容部分，包含模型生成的纯文本回复。定义于 <code>pydantic_ai/messages.py</code>。详见第 9 章。</p><p><strong>Tool</strong> 工具的封装类，包含执行函数、名称、描述、参数 schema 等信息。通过 <code>@agent.tool</code> 装饰器或直接构造创建。定义于 <code>pydantic_ai/tools.py</code>。详见第 5 章。</p><p><strong>ToolCallPart</strong> 模型响应中的工具调用部分，包含工具名称、调用参数和调用 ID。Agent 收到此 Part 后会执行对应工具并将结果作为 <code>ToolReturnPart</code> 发回。定义于 <code>pydantic_ai/messages.py</code>。详见第 9 章和第 11 章。</p><p><strong>ToolDefinition</strong> 工具的 schema 定义，包含名称、描述和 JSON Schema 格式的参数定义。传递给模型适配器，由模型决定是否调用。定义于 <code>pydantic_ai/tools.py</code>。详见第 5 章。</p><p><strong>ToolOutput</strong> 用于指定输出类型的包装类，可以附加自定义的工具名称和描述。当 <code>output_type</code> 需要额外配置时使用。详见第 12 章。</p><p><strong>ToolReturnPart</strong> 工具执行结果的消息部分，包含工具名称、返回值和对应的调用 ID。作为 <code>ModelRequest</code> 的一部分发送给模型。定义于 <code>pydantic_ai/messages.py</code>。详见第 9 章和第 11 章。</p><h2 id="u" tabindex="-1">U <a class="header-anchor" href="#u" aria-label="Permalink to &quot;U&quot;">​</a></h2><p><strong>Usage</strong> 记录 token 消耗数据的数据类，包含 <code>request_tokens</code>、<code>response_tokens</code>、<code>total_tokens</code> 和 <code>requests</code> 四个字段。每次模型请求后累加。定义于 <code>pydantic_ai/settings.py</code>。详见第 7 章和附录 B。</p><p><strong>UsageLimits</strong> 资源消耗限制配置，可设置 token 数量和请求次数的上限。当实际消耗超出限制时，Agent 会抛出 <code>UsageLimitExceeded</code> 异常。定义于 <code>pydantic_ai/settings.py</code>。详见第 4 章和附录 B。</p><p><strong>UserPromptPart</strong> 用户输入的消息部分，包含用户提供的文本提示。是 <code>ModelRequest</code> 中最常见的 Part 类型。定义于 <code>pydantic_ai/messages.py</code>。详见第 9 章。</p>',43)])])}const h=o(c,[["render",s]]);export{u as __pageData,h as default};
